+    // -- Enrichment: AbiDomOp target_element for all variants --
+
+    #[test]
+    fn abi_dom_op_target_all_variants() {
+        let ops = vec![
+            AbiDomOp::Create {
+                element_id: 1,
+                tag_index: 0,
+            },
+            AbiDomOp::Remove { element_id: 2 },
+            AbiDomOp::SetProp {
+                element_id: 3,
+                prop_index: 0,
+                value: vec![],
+            },
+            AbiDomOp::RemoveProp {
+                element_id: 4,
+                prop_index: 0,
+            },
+            AbiDomOp::SetText {
+                element_id: 5,
+                text: vec![],
+            },
+            AbiDomOp::Move {
+                element_id: 6,
+                new_parent: 0,
+                before: 0,
+            },
+        ];
+        for (i, op) in ops.iter().enumerate() {
+            assert_eq!(op.target_element(), (i + 1) as u32);
+        }
+    }
